///   5. Stop() is now async to allow graceful shutdown with a timeout.
///   6. Implements IDisposable to ensure cleanup.
/// </summary>
public class BackgroundProcessor : IDisposable
{
    private Task? _workerTask;
    private CancellationTokenSource? _cts;
    private bool _disposed;

    public void Start()
    {
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _workerTask = Task.Run(() => ProcessLoop(token), token);
    }

    private void ProcessLoop(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                // Pass the token into blocking calls so they unblock on cancel.
                // This is the critical migration step — if GetNextItem() blocks
                // indefinitely without a token, cancellation can't interrupt it.
                var item = GetNextItem(token);
                ProcessItem(item);
            }
            catch (OperationCanceledException) when (token.IsCancellationRequested)
            {
                // Replaces the old ThreadAbortException catch.
                // Unlike Thread.Abort(), this is cooperative — we arrive here
                // only when code explicitly checks/throws on the token.
                RollbackCurrentTransaction();
                break; // exit the loop cleanly; no ResetAbort() needed
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    public async Task StopAsync(TimeSpan? timeout = null)
    {
        timeout ??= TimeSpan.FromSeconds(2);

        if (_cts is null || _workerTask is null)
            return;

        // Signal cancellation (replaces setting _running = false AND Thread.Abort)
        _cts.Cancel();

        // Wait with a timeout instead of Thread.Sleep + Thread.Abort
        if (_workerTask != await Task.WhenAny(_workerTask, Task.Delay(timeout.Value)))
        {
            // Task didn't finish in time. Unlike .NET Framework, we CANNOT
            // force-kill it. Log a warning — this is a design-level concern.
            // See pitfall #3 below.
            Console.Error.WriteLine(
                "WARNING: Background processor did not stop within timeout.");
        }
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;

        _cts?.Cancel();
        // Use synchronous wait in Dispose; callers who need async should
        // call StopAsync() before disposing.
        _workerTask?.Wait(TimeSpan.FromSeconds(5));
        _cts?.Dispose();
    }

