    private object GetNextItem(CancellationToken token)
    {
        // PITFALL: The original GetNextItem() may use blocking APIs that
        // don't accept a CancellationToken (e.g., BlockingCollection.Take()
        // without a token, synchronous Socket.Receive, etc.).
        // You MUST refactor those call sites to pass the token through,
        // or they will hang on shutdown.
        token.ThrowIfCancellationRequested();
        return new object();
    }

    private void ProcessItem(object item) { }
    private void RollbackCurrentTransaction() { }
    private void FlushBuffers() { }
}

